<?php
namespace Tests\Feature;
use App\Jobs\ProcessReportExportJob;use App\Models\{DailyReport,MissingDailyReport,PerformanceScore,ReportExport,Task,TaskApproval,Team,User,Workspace,WorkProof};use App\Services\{EnterpriseModeService,PerformanceScoreService,ReportService};use App\Support\CurrentWorkspace;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Support\Facades\Storage;use Tests\TestCase;
class Phase6ReportingEnterpriseTest extends TestCase{use RefreshDatabase;private function ctx():array{$u=User::create(['name'=>'Owner','email'=>uniqid().'@e.com','password'=>'x','status'=>'active']);$w=Workspace::create(['name'=>'Acme','slug'=>uniqid('acme-'),'status'=>'active','owner_id'=>$u->id]);$w->users()->attach($u->id,['role_key'=>'workspace_owner','status'=>'active','joined_at'=>now()]);app(CurrentWorkspace::class)->set($w);return[$w,$u];}public function test_task_status_report_is_workspace_scoped():void{[$w,$u]=$this->ctx();$other=Workspace::create(['name'=>'Other','slug'=>uniqid('other-'),'status'=>'active']);Task::create(['workspace_id'=>$w->id,'task_number'=>'T-1','title'=>'In','priority'=>'high','status'=>'todo','created_by'=>$u->id]);Task::create(['workspace_id'=>$other->id,'task_number'=>'T-2','title'=>'Out','priority'=>'high','status'=>'todo']);$rows=app(ReportService::class)->taskStatusReport([]);$this->assertCount(1,$rows);$this->assertSame('In',$rows->first()->title);}public function test_overdue_no_update_proof_and_approval_reports_work():void{[$w,$u]=$this->ctx();$task=Task::create(['workspace_id'=>$w->id,'task_number'=>'T-1','title'=>'Overdue','priority'=>'high','status'=>'todo','due_date'=>today()->subDay(),'proof_required'=>true]);$this->assertCount(1,app(ReportService::class)->overdueTaskReport([]));$task->update(['updated_at'=>now()->subDays(10)]);$this->assertCount(1,app(ReportService::class)->noUpdateTaskReport(['days'=>7]));$this->assertCount(1,app(ReportService::class)->proofPendingReport([]));TaskApproval::create(['workspace_id'=>$w->id,'task_id'=>$task->id,'requested_by'=>$u->id,'status'=>'pending']);$this->assertCount(1,app(ReportService::class)->approvalPendingReport([]));}public function test_daily_missing_employee_and_team_reports_work():void{[$w,$u]=$this->ctx();$team=Team::create(['workspace_id'=>$w->id,'name'=>'Ops']);Task::create(['workspace_id'=>$w->id,'task_number'=>'T-1','title'=>'Done','priority'=>'medium','status'=>'completed','team_id'=>$team->id,'completed_by'=>$u->id,'completed_at'=>now()]);DailyReport::create(['workspace_id'=>$w->id,'user_id'=>$u->id,'report_date'=>today(),'status'=>'submitted']);MissingDailyReport::create(['workspace_id'=>$w->id,'user_id'=>$u->id,'report_date'=>today()->subDay(),'status'=>'missing']);app(PerformanceScoreService::class)->calculateDailyScore($w,$u,today());$svc=app(ReportService::class);$this->assertCount(1,$svc->dailyReportSubmissionReport([]));$this->assertCount(1,$svc->missingReportReport([]));$this->assertCount(1,$svc->employeePerformanceReport([]));$this->assertCount(1,$svc->teamPerformanceReport([]));}public function test_export_request_and_job_create_private_file_and_cross_workspace_download_is_forbidden():void{Storage::fake('local');[$w,$u]=$this->ctx();$this->actingAs($u);$export=ReportExport::create(['workspace_id'=>$w->id,'user_id'=>$u->id,'report_key'=>'task_status','format'=>'csv','status'=>'pending']);(new ProcessReportExportJob($export))->handle(app(\App\Services\ExportService::class),app(CurrentWorkspace::class));$this->assertSame('completed',$export->refresh()->status);Storage::disk('local')->assertExists($export->file_path);$other=Workspace::create(['name'=>'Other','slug'=>uniqid('other-'),'status'=>'active']);app(CurrentWorkspace::class)->set($other);$this->get('/reports/exports/'.$export->id.'/download')->assertNotFound();}public function test_enterprise_flags_private_default_workspace_and_score_model():void{[$w,$u]=$this->ctx();config(['workproof.saas_enabled'=>false,'workproof.billing_enabled'=>false,'workproof.multi_tenant_enabled'=>false,'workproof.edition'=>'private']);$this->assertFalse(app(EnterpriseModeService::class)->billingEnabled());$this->assertSame($w->id,app(EnterpriseModeService::class)->resolveDefaultWorkspace()->id);$this->get('/register')->assertNotFound();$this->assertDatabaseMissing('performance_scores',['user_id'=>999]);} }
